+fn csv_escape(value: &str, sep: char) -> String {
+    if value.contains(sep) || value.contains('"') || value.contains('\n') {
+        let mut escaped = String::with_capacity(value.len() + 2);
+        escaped.push('"');
+        for ch in value.chars() {
+            if ch == '"' {
+                escaped.push('"');
+            }
+            escaped.push(ch);
+        }
+        escaped.push('"');
+        escaped
+    } else {
+        value.to_owned()
+    }
+}
